@Test
public void testParseOctalAllSpaces() throws Exception {
    byte[] buffer = "    ".getBytes(CharsetNames.UTF_8); // All spaces
    try {
        TarUtils.parseOctal(buffer, 0, buffer.length);
        fail("Expected IllegalArgumentException - no octal digits");
    } catch (IllegalArgumentException expected) {
    }
}

@Test
public void testParseOctalTrailingNulsOnly() throws Exception {
    byte[] buffer = new byte[]{0, 0, 0, 0}; // All NULs
    long result = TarUtils.parseOctal(buffer, 0, buffer.length);
    assertEquals(0L, result);
}

@Test
public void testParseOctalLeadingSpacesTrailingSpaces() throws Exception {
    byte[] buffer = "   \0\0\0".getBytes(CharsetNames.UTF_8); // Leading spaces, trailing NULs
    try {
        TarUtils.parseOctal(buffer, 0, buffer.length);
        fail("Expected IllegalArgumentException - no octal digits");
    } catch (IllegalArgumentException expected) {
    }
}

@Test
pubic void testParseOctalSingleDigitWithTrailing() throws Exception {
    byte[] buffer = " 7\0 ".getBytes(CharsetNames.UTF_8); // Single octal digit
    long result = TarUtils.parseOctal(buffer, 0, buffer.length);
    assertEquals(7L, result);
}
